import{_ as t}from"./chunks/homepage.DZZjIHGg.js";import{_ as a,a as r,b as o,c as i,d as s}from"./chunks/output.C9LXqVDV.js";import{_ as n,o as l,c as d,ae as c}from"./chunks/framework.C00B0EYs.js";const _=JSON.parse('{"title":"Getting Started","description":"First-run guidance for Motor Sound Editor users.","frontmatter":{"title":"Getting Started","description":"First-run guidance for Motor Sound Editor users."},"headers":[],"relativePath":"docs/guide/getting-started.md","filePath":"docs/guide/getting-started.md"}'),p={name:"docs/guide/getting-started.md"};function h(g,e,u,m,f,k){return l(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>Motor Sound Editor is built for creators who want to design layered motor sound projects in a visual editor instead of hand-maintaining raw simulator tables. The current version is focused on three core workflows already implemented in the desktop app: project authoring, real-time preview, and export packaging.</p><p><img src="'+t+'" alt="Motor Sound Editor home screen"></p><h2 id="_1-preparation" tabindex="-1">1. Preparation <a class="header-anchor" href="#_1-preparation" aria-label="Permalink to &quot;1. Preparation&quot;">​</a></h2><h3 id="operating-system" tabindex="-1">Operating system <a class="header-anchor" href="#operating-system" aria-label="Permalink to &quot;Operating system&quot;">​</a></h3><p><strong>Windows</strong> is the primary supported platform today.</p><h3 id="download-and-install" tabindex="-1">Download and install <a class="header-anchor" href="#download-and-install" aria-label="Permalink to &quot;Download and install&quot;">​</a></h3><ul><li><strong>Get the app</strong>: Download the current Windows installer directly from <a href="https://github.com/xiangao0904/Motor-Sound-Editor/releases/download/v1.0.0/Motor.Sound.Editor_1.0.0_x64-setup.exe" target="_blank" rel="noreferrer">this release link</a>.</li><li><strong>Quick install</strong>: After downloading, run the installer. No extra runtime setup is required because the Tauri dependencies are already bundled with the app.</li></ul><h3 id="example-files" tabindex="-1">Example files <a class="header-anchor" href="#example-files" aria-label="Permalink to &quot;Example files&quot;">​</a></h3><p>If you want working <code>.msep</code> projects to inspect right away, start with these examples:</p><ul><li><a href="https://github.com/xiangao0904/Motor-Sound-Editor/releases/download/v1.0.0/caf_train_sound.msep" target="_blank" rel="noreferrer">caf_train_sound.msep</a> — Contributor: lx9702</li><li><a href="https://github.com/xiangao0904/Motor-Sound-Editor/releases/download/v1.0.0/class323.msep" target="_blank" rel="noreferrer">class323.msep</a> — Contributor: K.L1</li></ul><h3 id="data-and-assets" tabindex="-1">Data and assets <a class="header-anchor" href="#data-and-assets" aria-label="Permalink to &quot;Data and assets&quot;">​</a></h3><ul><li><strong>Assets</strong>: Prepare at least one motor sound source file in <code>.wav</code> or <code>.ogg</code>.</li><li><strong>Parameters</strong>: Prepare the train&#39;s basic performance values, such as maximum speed, acceleration, and brake deceleration.</li></ul><h2 id="_2-core-workflow" tabindex="-1">2. Core workflow <a class="header-anchor" href="#_2-core-workflow" aria-label="Permalink to &quot;2. Core workflow&quot;">​</a></h2><p>You can experience the main features of the app through these six steps:</p><h3 id="step-1-create-a-project" tabindex="-1">Step 1: Create a project <a class="header-anchor" href="#step-1-create-a-project" aria-label="Permalink to &quot;Step 1: Create a project&quot;">​</a></h3><p><img src="'+a+'" alt="New project"></p><ol><li>Launch the app and click <strong>New Project</strong> on the Home screen.</li><li>Enter a project name such as <code>MyTrainMotor</code>.</li><li>Set defaults such as <strong>Max Speed</strong> and <strong>Acceleration</strong>.</li><li>Confirm and enter the editor.</li></ol><h3 id="step-2-manage-tracks-and-import-audio" tabindex="-1">Step 2: Manage tracks and import audio <a class="header-anchor" href="#step-2-manage-tracks-and-import-audio" aria-label="Permalink to &quot;Step 2: Manage tracks and import audio&quot;">​</a></h3><p><img src="'+r+'" alt="Import audio"></p><ol><li>In <strong>Track Layers</strong>, make sure there is an active track.</li><li>In <strong>Track Details</strong>, click the file picker icon.</li><li>Choose a <code>.wav</code> or <code>.ogg</code> audio file.</li></ol><h3 id="step-3-draw-pitch-and-volume-curves" tabindex="-1">Step 3: Draw pitch and volume curves <a class="header-anchor" href="#step-3-draw-pitch-and-volume-curves" aria-label="Permalink to &quot;Step 3: Draw pitch and volume curves&quot;">​</a></h3><p><img src="'+o+'" alt="Draw curves"></p><ol><li>Switch to <strong>Keyframe</strong> mode in the toolbar.</li><li>Add keyframes for <strong>Traction Pitch</strong> and <strong>Traction Volume</strong> in the chart. Left click adds a point and right click removes one.</li><li>For finer control, switch to <strong>Move</strong> mode to drag keyframes or edit values directly in <strong>List Editor</strong>.</li></ol><h3 id="step-4-preview-in-real-time" tabindex="-1">Step 4: Preview in real time <a class="header-anchor" href="#step-4-preview-in-real-time" aria-label="Permalink to &quot;Step 4: Preview in real time&quot;">​</a></h3><p><img src="'+i+'" alt="Real-time preview"></p><ol><li>Press <code>Space</code> to start playback.</li><li>Use <code>W</code> to move the state toward traction and <code>S</code> to move it toward brake.</li><li>Adjust <strong>Current Speed</strong>, or switch to <strong>Select</strong> mode and click empty space in the chart to change preview speed quickly.</li></ol><h3 id="step-5-save-the-project" tabindex="-1">Step 5: Save the project <a class="header-anchor" href="#step-5-save-the-project" aria-label="Permalink to &quot;Step 5: Save the project&quot;">​</a></h3><ul><li>Press <code>Ctrl+S</code> to save the project as <code>.msep</code>.</li><li><code>.msep</code> is the app&#39;s native project format. It packages project settings, curve data, and audio assets together so the project stays portable and editable.</li></ul><h3 id="step-6-export-a-bve-package" tabindex="-1">Step 6: Export a BVE package <a class="header-anchor" href="#step-6-export-a-bve-package" aria-label="Permalink to &quot;Step 6: Export a BVE package&quot;">​</a></h3><p><img src="'+s+'" alt="Export"></p><ol><li>Click <strong>Export</strong> in the toolbar or menu.</li><li>Choose <strong>BVE</strong> in the dialog.</li><li>Select a sample rate, usually <code>44100 Hz</code>.</li><li>The app generates a <code>.zip</code> package containing the required BVE files such as <code>vehicle.txt</code>, <code>motornoise.txt</code>, and converted WAV audio.</li></ol><h2 id="_3-common-shortcuts" tabindex="-1">3. Common shortcuts <a class="header-anchor" href="#_3-common-shortcuts" aria-label="Permalink to &quot;3. Common shortcuts&quot;">​</a></h2><p>A small set of shortcuts already covers most of the daily editing loop:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Shortcut</th><th style="text-align:left;">Action</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Space</strong></td><td style="text-align:left;">Play / pause preview</td></tr><tr><td style="text-align:left;"><strong>W</strong></td><td style="text-align:left;">Move the state toward traction</td></tr><tr><td style="text-align:left;"><strong>S</strong></td><td style="text-align:left;">Move the state toward brake</td></tr><tr><td style="text-align:left;"><strong>Ctrl+S</strong></td><td style="text-align:left;">Save the project</td></tr><tr><td style="text-align:left;"><strong>Ctrl+Z / Ctrl+Y</strong></td><td style="text-align:left;">Undo / redo</td></tr><tr><td style="text-align:left;"><strong>Delete</strong></td><td style="text-align:left;">Delete the selected keyframe</td></tr></tbody></table>',35)])])}const v=n(p,[["render",h]]);export{_ as __pageData,v as default};
